def parse_basic_auth(auth_header: str):
    try:
        scheme, b64 = auth_header.split(" ", 1)
        if scheme.lower() != "basic":
            return None, None
        import base64

        raw = base64.b64decode(b64.strip()).decode("utf-8")
        if ":" not in raw:
            return None, None
        client_id, client_secret = raw.split(":", 1)
        return client_id, client_secret
    except Exception:
        return None, None


